class Hospital {
  name: String
  address: String
}

class ExaminationType {
  name: String
  description: String
}

class Permission {
  hospital: Hospital
  examinationType: ExaminationType
  granted: Boolean
  dateGranted: Date
}

class TreatmentPlan {
  name: String
  problemType: String
  examinations: ExaminationType*
}

class Patient {
  name: String
  dateOfBirth: Date
}

class Doctor {
  name: String
  hospital: Hospital
}

class Diagnosis {
  patient: Patient
  doctor: Doctor
  problemType: String
  date: Date
}

class ActualTreatment {
  diagnosis: Diagnosis
  treatmentPlan: TreatmentPlan
  examinations: ExaminationType*
  medicalActions: String*
}

class Examination {
  actualTreatment: ActualTreatment
  examinationType: ExaminationType
  hospital: Hospital
  date: Date
}

Hospital --* Permission
ExaminationType --* Permission
TreatmentPlan --* ExaminationType
Patient --* Diagnosis
Doctor --* Diagnosis
Diagnosis --* ActualTreatment
ActualTreatment --* Examination
ActualTreatment --* TreatmentPlan
@end,"[

