class Kinepolis {
}
class Cinema {
  name: String
  address: String
}
class Theatre {
  name: String
  seats: Integer
}
class Movie {
  title: String
}
class Copy {
  movie: Movie
  cinema: Cinema
}
class Show {
  copy: Copy
  theatre: Theatre
  startDate: Date
  endDate: Date
  cancelled: Boolean
}
class Reservation {
  show: Show
  seatNumber: Integer
  customerName: String
  creditCard: String
  paid: Boolean
  cancelled: Boolean
}
class Ticket {
  show: Show
  seatNumber: Integer
  price: Decimal
}
Kinepolis *-- Cinema
Cinema *-- Theatre
Cinema *-- Copy
Theatre *-- Show
Movie *-- Copy
Copy *-- Show
Show *-- Reservation
Show *-- Ticket
Reservation -- Ticket
@enduml""

    ""code"": ""class Traveller {
  name : String
  billingInformation : BillingInformation
  travelPreferences : TravelPreference*
}

class BillingInformation {
  company_name : String
  company_address : String
  creditCardInformation : CreditCardInformation
}

class CreditCardInformation {
  cardNumber : String
  expirationDate : Date
  cvv : String
}

class TravelPreference {
  preference : String
}

class Hotel {
  name : String
  address : String
  hotelChain : HotelChain
  availableRooms : Room*
}

class HotelChain {
  name : String
}

class Room {
  type : String
  rating : Integer
  price : Decimal
}

class Booking {
  traveller : Traveller
  hotel : Hotel
  arrivalDate : Date
  departureDate : Date
  numberOfRooms : Integer
  roomType : String
  budget : Decimal
  travelPreferences : TravelPreference*
  bookingStatus : String
  reliabilityRating : Integer
  cancellationDeadline : Date
}

class PreliminaryBooking {
  booking : Booking
  keyParameters : KeyParameters
}

class KeyParameters {
  price : Decimal
  cityArea : String
  hotelRating : Integer
  keyPreferences : TravelPreference*
  uniqueBookingIdentifier : String
}

class SpecialOffer {
  hotel : Hotel
  price : Decimal
  travelPreferences : TravelPreference*
}
